.demon-custom label{display:block;font-size:12px;color:var(--text-dim);margin-bottom:5px}
.demon-custom textarea{width:100%;min-height:100px;padding:12px;border-radius:10px;background:rgba(255,255,255,0.05);border:1px solid var(--border);color:var(--text);font-size:13px;resize:vertical;font-family:inherit}
</style>
</head>
<body>
<div class="C">
  <div class="tb"><h1>帝王战队</h1><div class="sub">开局设定</div></div>
  <div class="si" id="steps"></div>
  <div class="screen active" id="s0">
    <div class="st">选择身份</div>
    <div class="opt-list">
      <div class="opt" data-type="identity" data-value="收服者"><span class="ic">⚔️</span><div><div class="lb">收服者</div><div class="ds">以征服者身份进入，收服英雄们，建立你的后宫</div></div></div>
      <div class="opt" data-type="identity" data-value="小英雄"><span class="ic">🛡️</span><div><div class="lb">小英雄</div><div class="ds">以英雄身份进入，面对被俘命运，体验被征服的快感</div></div></div>
      <div class="opt" data-type="identity" data-value="魔王"><span class="ic">👑</span><div><div class="lb">魔王</div><div class="ds">以魔王身份进入，统治一切，无需选择目标角色</div></div></div>
    </div>
  </div>
  <div class="screen" id="s1">
    <div class="st">选择阵营</div>
    <div class="opt-list">
      <div class="opt" data-type="faction" data-value="联邦"><span class="ic">🏛️</span><div><div class="lb">联邦</div><div class="ds">维护世界和平的官方组织</div></div></div>
      <div class="opt" data-type="faction" data-value="魔神会"><span class="ic">🔮</span><div><div class="lb">魔神会</div><div class="ds">追求欲望与力量的邪恶组织</div></div></div>
      <div class="opt" data-type="faction" data-value="地下势力"><span class="ic">🌑</span><div><div class="lb">地下势力</div><div class="ds">控制地下经济的犯罪网络</div></div></div>
      <div class="opt" data-type="faction" data-value="猎人协会"><span class="ic">🎯</span><div><div class="lb">猎人协会</div><div class="ds">独立的英雄雇佣组织</div></div></div>
    </div>
    <div class="btn-row"><button class="btn btn-s back-btn" data-target="s0">返回</button></div>
  </div>
  <div class="screen" id="s2">
    <div class="st">选择职业</div>
    <div class="faction-desc" id="faction-desc" style="display:none"></div>
    <div class="opt-list" id="class-list"></div>
    <div class="btn-row"><button class="btn btn-s back-btn" data-target="s1">返回</button></div>
  </div>
  <div class="screen" id="s3">
    <div class="st">自定义档案</div>
    <div class="fm">
      <div class="fm-row">
        <div class="fg"><label>姓名</label><input type="text" id="f-name" placeholder="角色姓名"/></div>
        <div class="fg"><label>年龄</label><input type="text" id="f-age" placeholder="年龄"/></div>
        <div class="fg"><label>身高(cm)</label><input type="text" id="f-height" placeholder="身高"/></div>
      </div>
      <div class="fm-row">
        <div class="fg"><label>体重(kg)</label><input type="text" id="f-weight" placeholder="体重"/></div>
        <div class="fg"><label>阴茎尺寸(cm)</label><input type="text" id="f-penis" placeholder="尺寸"/></div>
        <div class="fg"><label>特殊能力</label><input type="text" id="f-ability" placeholder="你的异能或技能"/></div>
      </div>
      <div class="fm-row-1 custom-full">
        <div class="fg"><label>自定义设定（选填，将覆盖上面所有设定直接发送）</label><textarea id="f-custom" placeholder="在此输入你的完整角色设定，如果填写了此项，上面的字段将被忽略"></textarea></div>
      </div>
    </div>
    <div class="btn-row"><button class="btn btn-s back-btn" data-target="s2">返回</button><button class="btn btn-p" id="to-s4">下一步</button></div>
  </div>
  <div class="screen" id="s4">
    <div class="st">选择目标角色（悬停查看详情）</div>
    <div class="hero-grid" id="hero-grid"></div>
    <div class="btn-row"><button class="btn btn-s back-btn" data-target="s3">返回</button></div>
  </div>
  <div class="screen" id="s5">
    <div class="st">自定义角色</div>
    <div class="fm">
      <div class="fm-row">
        <div class="fg"><label>姓名</label><input type="text" id="ch-name" placeholder="角色姓名"/></div>
        <div class="fg"><label>年龄</label><input type="text" id="ch-age" placeholder="年龄"/></div>
        <div class="fg"><label>阴茎尺寸(cm)</label><input type="text" id="ch-penis" placeholder="尺寸"/></div>
      </div>
      <div class="fm-row">
        <div class="fg"><label>身高(cm)</label><input type="text" id="ch-height" placeholder="身高"/></div>
        <div class="fg"><label>体重(kg)</label><input type="text" id="ch-weight" placeholder="体重"/></div>
        <div class="fg"><label>第二性器</label><select id="ch-sexorgan"><option value="">请选择</option><option value="足部">足部</option><option value="胸腹腿内侧">胸腹腿内侧</option><option value="肉棒">肉棒</option><option value="魔能系带">魔能系带</option><option value="时空腺体">时空腺体</option><option value="后穴">后穴</option><option value="分身共享">分身共享</option><option value="乳头">乳头</option><option value="耳朵">耳朵</option><option value="尾巴">尾巴</option><option value="其他">其他</option></select></div>
      </div>
      <div class="fm-row-1 custom-full">
        <div class="fg"><label>自定义角色设定（选填）</label><textarea id="ch-custom" placeholder="在此输入你的完整角色设定"></textarea></div>
      </div>
    </div>
    <div class="btn-row"><button class="btn btn-s back-btn" data-target="s4">返回</button><button class="btn btn-p" id="confirm-custom">确认角色</button></div>
  </div>
  <div class="screen" id="s6">
    <div class="st">确认设定</div>
    <div class="summary-box" id="summary-content"></div>
    <div class="btn-row"><button class="btn btn-s back-btn" data-target="s4">返回修改</button><button class="btn btn-p" id="confirm-and-start">开始游戏</button></div>
  </div>
  <div class="screen" id="s7">
    <div class="st">魔王设定</div>
    <div class="demon-custom">
      <label>请描述你的魔王身份（选填）</label>
      <textarea id="demon-custom" placeholder="在此输入你的魔王设定，包括身份背景、特殊能力、外貌特征、性格特点、性癖偏好等..."></textarea>
    </div>
    <div class="summary-box" id="summary-demon"></div>
    <div class="btn-row"><button class="btn btn-s back-btn" data-target="s0">返回修改</button><button class="btn btn-p" id="start-demon">开始游戏</button></div>
  </div>
</div>
<script>
$(document).ready(function(){
var selections={identity:'',faction:'',cls:'',profile:{},hero:'',heroProfile:{}};
var F_DESC={'联邦':'维护世界和平的官方组织，拥有先进的科技与强大的军事力量。联邦英雄们接受严格训练，以守护人类为己任。','魔神会':'追求欲望与力量的邪恶组织，成员崇拜魔神，通过禁忌魔法获得超凡能力。他们蔑视秩序，以力量为尊。','地下势力':'控制地下经济的庞大犯罪网络，业务涵盖拍卖、情报、武器走私等。成员多为亡命之徒，行事狠辣。','猎人协会':'独立的英雄雇佣组织，以佣金形式派遣英雄执行任务。协会不依附任何势力，只认金钱与契约。'};
var F={'联邦':{name:'联邦',cj:['指挥官','科学家','情报官'],hj:['学员']},'魔神会':{name:'魔神会',cj:['教皇','千面主教','红衣使徒'],hj:['实验体','俘虏','堕落英雄']},'地下势力':{name:'地下势力',cj:['大统领','情报贩子','拍卖师'],hj:['角斗士','商品','逃亡者']},'猎人协会':{name:'猎人协会',cj:['协会长','王牌猎人'],hj:['见习猎人','委托目标']}};
var HEROES=[{n:'问天',a:'祖龙',t:'力量S/魔法SSS',fetish:'足部崇拜，精牛狂魔',personality:'高傲冷峻，服从强者',look:'银白长发，金色竖瞳，身披龙鳞战甲'},{n:'千瑞',a:'大地',t:'力量SSS/魔法S',fetish:'被当作便器使用',personality:'温柔顺从，内心渴望被征服',look:'黑长直，翠绿眼眸，肌肤如雪'},{n:'子夜',a:'乾坤',t:'力量SS/魔法SS',fetish:'精牛，渴望被大量播种',personality:'神秘莫测，表面矜持实则浪荡',look:'紫黑短发，琥珀色眼瞳，冷峻禁欲'},{n:'阚泽',a:'超能',t:'力量SSS/魔法SSS',fetish:'被当作娼年支配',personality:'傲娇毒舌，内心渴望被驯服',look:'粉紫短发，桃花眼，精致娃娃脸'},{n:'凯风',a:'时空',t:'力量S/魔法S',fetish:'被开发时空腺体，无法自控',personality:'活泼开朗，擅长撩拨却不经操',look:'浅蓝短发，淡蓝异瞳，纤细少年'},{n:'空耀',a:'轮回',t:'力量SSS/魔法S',fetish:'后穴开发，身体被改造成肉便器',personality:'禁欲系外表下隐藏淫荡本性',look:'黑曜短发，暗红眼眸，肌肉匀称'},{n:'嘉陵',a:'神魔',t:'力量SS/魔法SSS',fetish:'神魔双修，雌堕改造',personality:'亦正亦邪，被改造后彻底臣服',look:'墨绿长发，金紫异瞳，神魔双相'},{n:'岚云',a:'幻狐',t:'力量S/魔法S',fetish:'魅惑系，擅长勾引却被反操',personality:'妖媚多情，实则纯情易推倒',look:'橘红长发，狐狸眼，九尾幻化'},{n:'启润',a:'怒风',t:'力量SS/魔法S',fetish:'暴力驯服，在痛苦中获取快感',personality:'暴躁易怒，被压制后反而兴奋',look:'火红短发，虎牙外露，狂野不羁'},{n:'星野',a:'九龙',t:'力量SSS/魔法SS',fetish:'九龙乱交，群体征服',personality:'霸道总裁型，不服输最终臣服',look:'黑金短发，九芒星瞳孔，龙角印记'}];
var STEPS={'收服者':['身份','阵营','职业','档案','角色','确认'],'小英雄':['身份','阵营','职业','角色','确认'],'魔王':['身份','确认']};
var SCREENS={'收服者':['s0','s1','s2','s3','s4','s6'],'小英雄':['s0','s1','s2','s4','s6'],'魔王':['s0','s7']};
function nav(id){$('.screen').removeClass('active');$('#'+id).addClass('active');var screens=SCREENS[selections.identity]||SCREENS['收服者'];var idx=screens.indexOf(id);var steps=STEPS[selections.identity]||STEPS['收服者'];var h='';for(var i=0;i<steps.length;i++){if(i<idx)h+='<div class="sd done"></div>';else if(i===idx)h+='<div class="sd active"></div>';else h+='<div class="sd"></div>';}$('#steps').html(h);}
function renderClasses(){var list=[];var factionData=F[selections.faction];if(factionData){list=selections.identity==='收服者'?factionData.cj:factionData.hj;}var h='';for(var i=0;i<list.length;i++){h+='<div class="opt" data-type="class" data-value="'+list[i]+'"><span class="ic">⚡</span><div><div class="lb">'+list[i]+'</div></div></div>';}$('#class-list').html(h);var desc=F_DESC[selections.faction]||'';if(desc){$('#faction-desc').html('<div class="desc-title">'+F[selections.faction].name+'简介</div>'+desc).show();}else{$('#faction-desc').hide();}}
function renderHeroes(){var h='';for(var i=0;i<HEROES.length;i++){var hero=HEROES[i];h+='<div class="hc" data-type="hero" data-value="'+hero.n+'"><div class="hn">'+hero.n+'</div><div class="ha">'+hero.a+'</div><div class="ht">'+hero.t+'</div><div class="hd">性癖：'+hero.fetish+'</div></div>';}h+='<div class="hc custom" data-type="hero" data-value="自定义"><span class="ic" style="font-size:28px">✨</span><div><div class="hn">自定义角色</div><div class="ha">创建你自己的英雄角色</div></div></div>';$('#hero-grid').html(h);if(selections.identity==='小英雄'){$('.screen#s4 .back-btn').attr('data-target','s2');}else{$('.screen#s4 .back-btn').attr('data-target','s3');}}
function collectProfile(){selections.profile={name:$('#f-name').val(),age:$('#f-age').val(),height:$('#f-height').val(),weight:$('#f-weight').val(),penis:$('#f-penis').val(),ability:$('#f-ability').val(),custom:$('#f-custom').val()};}
function collectCustomHero(){selections.heroProfile={name:$('#ch-name').val(),age:$('#ch-age').val(),penis:$('#ch-penis').val(),height:$('#ch-height').val(),weight:$('#ch-weight').val(),sexorgan:$('#ch-sexorgan').val(),custom:$('#ch-custom').val()};}
function getHeroInfo(heroName){for(var i=0;i<HEROES.length;i++){if(HEROES[i].n===heroName)return HEROES[i];}return null;}
function buildUserString(){if(selections.identity==='小英雄'){var parts=[];parts.push('身份：小英雄');if(selections.faction)parts.push('阵营：'+selections.faction);if(selections.cls)parts.push('职业：'+selections.cls);return parts.join('，');}if(selections.profile.custom){return selections.profile.custom;}var parts=[];parts.push('身份：'+selections.identity);if(selections.faction)parts.push('阵营：'+selections.faction);if(selections.cls)parts.push('职业：'+selections.cls);if(selections.profile.name)parts.push('姓名：'+selections.profile.name);if(selections.profile.age)parts.push('年龄：'+selections.profile.age);if(selections.profile.height)parts.push('身高：'+selections.profile.height+'cm');if(selections.profile.weight)parts.push('体重：'+selections.profile.weight+'kg');if(selections.profile.penis)parts.push('阴茎尺寸：'+selections.profile.penis+'cm');if(selections.profile.ability)parts.push('特殊能力：'+selections.profile.ability);return parts.join('，');}
function buildHeroString(){if(selections.identity==='魔王')return '';if(selections.hero==='自定义'){if(selections.heroProfile.custom){return '目标角色：'+selections.heroProfile.custom;}var parts=[];parts.push('目标角色：自定义');if(selections.heroProfile.name)parts.push('姓名：'+selections.heroProfile.name);if(selections.heroProfile.age)parts.push('年龄：'+selections.heroProfile.age);if(selections.heroProfile.height)parts.push('身高：'+selections.heroProfile.height+'cm');if(selections.heroProfile.weight)parts.push('体重：'+selections.heroProfile.weight+'kg');if(selections.heroProfile.penis)parts.push('阴茎尺寸：'+selections.heroProfile.penis+'cm');if(selections.heroProfile.sexorgan)parts.push('第二性器：'+selections.heroProfile.sexorgan);return parts.join('，');}var hero=getHeroInfo(selections.hero);if(hero){return '目标角色：'+hero.n+'（'+hero.a+'）\n属性：'+hero.t+'\n性癖：'+hero.fetish+'\n性格：'+hero.personality+'\n外貌：'+hero.look;}return '目标角色：'+selections.hero;}
function buildSummary(){var container=$('#summary-content');var p=selections.profile;var html='';html+='<div class="summary-section"><h3>基础信息</h3>';html+='<div class="summary-item"><span class="summary-label">身份</span><span class="summary-value">'+selections.identity+'</span></div>';html+='<div class="summary-item"><span class="summary-label">阵营</span><span class="summary-value">'+(selections.faction||'未选择')+'</span></div>';html+='<div class="summary-item"><span class="summary-label">职业</span><span class="summary-value">'+(selections.cls||'未选择')+'</span></div>';html+='</div>';if(p.custom){html+='<div class="summary-section"><h3>自定义设定</h3><div class="custom-section"><div class="summary-value" style="white-space:pre-wrap;font-size:12px">'+p.custom+'</div></div></div>';}if(selections.identity!=='小英雄'&&(p.name||p.age||p.height||p.weight||p.penis||p.ability)){html+='<div class="summary-section"><h3>详细档案</h3>';if(p.name)html+='<div class="summary-item"><span class="summary-label">姓名</span><span class="summary-value">'+p.name+'</span></div>';if(p.age)html+='<div class="summary-item"><span class="summary-label">年龄</span><span class="summary-value">'+p.age+'</span></div>';if(p.height)html+='<div class="summary-item"><span class="summary-label">身高</span><span class="summary-value">'+p.height+'cm</span></div>';if(p.weight)html+='<div class="summary-item"><span class="summary-label">体重</span><span class="summary-value">'+p.weight+'kg</span></div>';if(p.penis)html+='<div class="summary-item"><span class="summary-label">阴茎尺寸</span><span class="summary-value">'+p.penis+'cm</span></div>';if(p.ability)html+='<div class="summary-item"><span class="summary-label">特殊能力</span><span class="summary-value">'+p.ability+'</span></div>';html+='</div>';}if(selections.identity!=='魔王'){html+='<div class="summary-section"><h3>目标角色</h3>';if(selections.hero==='自定义'){var h=selections.heroProfile;if(h.custom){html+='<div class="custom-section"><div class="summary-value" style="white-space:pre-wrap;font-size:12px">'+h.custom+'</div></div>';}else{if(h.name)html+='<div class="summary-item"><span class="summary-label">姓名</span><span class="summary-value">'+h.name+'</span></div>';if(h.age)html+='<div class="summary-item"><span class="summary-label">年龄</span><span class="summary-value">'+h.age+'</span></div>';if(h.height)html+='<div class="summary-item"><span class="summary-label">身高</span><span class="summary-value">'+h.height+'cm</span></div>';if(h.weight)html+='<div class="summary-item"><span class="summary-label">体重</span><span class="summary-value">'+h.weight+'kg</span></div>';if(h.penis)html+='<div class="summary-item"><span class="summary-label">阴茎尺寸</span><span class="summary-value">'+h.penis+'cm</span></div>';if(h.sexorgan)html+='<div class="summary-item"><span class="summary-label">第二性器</span><span class="summary-value">'+h.sexorgan+'</span></div>';}if(!h.name&&!h.custom)html+='<div class="summary-item"><span class="summary-value">未填写详细信息</span></div>';}else{var hero=getHeroInfo(selections.hero);if(hero){html+='<div class="summary-item"><span class="summary-label">角色名</span><span class="summary-value">'+hero.n+'（'+hero.a+'）</span></div>';html+='<div class="summary-item"><span class="summary-label">属性</span><span class="summary-value">'+hero.t+'</span></div>';html+='<div class="summary-item"><span class="summary-label">性癖</span><span class="summary-value">'+hero.fetish+'</span></div>';html+='<div class="summary-item"><span class="summary-label">性格</span><span class="summary-value">'+hero.personality+'</span></div>';html+='<div class="summary-item"><span class="summary-label">外貌</span><span class="summary-value">'+hero.look+'</span></div>';}else{html+='<div class="summary-item"><span class="summary-label">角色名</span><span class="summary-value">'+selections.hero+'</span></div>';}}html+='</div>';}container.html(html);}
function buildDemonSummary(){var container=$('#summary-demon');var demonCustom=$('#demon-custom').val();var html='';html+='<div class="summary-section"><h3>魔王信息</h3>';html+='<div class="summary-item"><span class="summary-label">身份</span><span class="summary-value">魔王</span></div>';html+='</div>';if(demonCustom){html+='<div class="summary-section"><h3>魔王设定</h3><div class="custom-section"><div class="summary-value" style="white-space:pre-wrap;font-size:12px">'+demonCustom+'</div></div></div>';}else{html+='<div class="summary-section"><h3>提示</h3><div class="summary-item"><span class="summary-value">请在上方填写你的魔王设定</span></div></div>';}container.html(html);}
function sendMessage(){var userStr=buildUserString();var heroStr=buildHeroString();var finalMessage=userStr+(heroStr?'\n'+heroStr:'');try{if(typeof triggerSlash==='function'){triggerSlash('/send '+finalMessage+'|/trigger');toastr.success('设定已注入聊天栏！','发送成功');}else{throw new Error('triggerSlash not found');}}catch(e){navigator.clipboard.writeText(finalMessage).then(function(){toastr.info('已复制到剪贴板，请手动粘贴','发送回退');}).catch(function(){toastr.error('发送失败，请手动复制','错误');});}}
